// Each ensures-forall is duplicated with `self` substituted by `post1_self_`
// and `post2_self_`, but every per-run trigger (post1_self_.get_container(c),
// post1_self_.get_proc(p), post1_self_.get_thread(t), ...) is disjoint from
// its post2 counterpart, so z3 never instantiates the two runs at the same
// skolem witness. The asserts below introduce a fused witness — they speak of
// BOTH post1_self_ and post2_self_ at the same index — and inside each
// `by { }` body we additionally assert the post2-domain-membership, which is
// the only extra hypothesis the post2 ensures-forall needs to fire. Once the
// two runs are aligned, the shared `pre_self_` chains the equality through:
//     post1_self_.X(p) = pre_self_.X(p) = post2_self_.X(p).
// Nothing in the prelude is asserted on faith — each follows from the two
// copies of the ensures plus the matching domain hypothesis.

let par_ptr: ProcPtr = pre_self_.get_proc(proc_ptr).parent.unwrap();

// ---- Domain equalities (both runs perform the same domain transformation). ----
assert(post1_self_.container_dom() =~= post2_self_.container_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());

// ---- containers_tree_unchanged: trigger pre_self_.get_container(c_ptr) is
// shared between both ensures-foralls; the per-run conclusion is the same set
// of five field equalities against pre_self_. Bridge them field by field. ----
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr)
        implies post1_self_.get_container(c_ptr).parent
            =~= post2_self_.get_container(c_ptr).parent by {
    assert(post2_self_.container_dom().contains(c_ptr));
};
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr)
        implies post1_self_.get_container(c_ptr).children
            =~= post2_self_.get_container(c_ptr).children by {
    assert(post2_self_.container_dom().contains(c_ptr));
};
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr)
        implies post1_self_.get_container(c_ptr).uppertree_seq
            =~= post2_self_.get_container(c_ptr).uppertree_seq by {
    assert(post2_self_.container_dom().contains(c_ptr));
};
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr)
        implies post1_self_.get_container(c_ptr).subtree_set
            =~= post2_self_.get_container(c_ptr).subtree_set by {
    assert(post2_self_.container_dom().contains(c_ptr));
};
assert forall|c_ptr: ContainerPtr|
    post1_self_.container_dom().contains(c_ptr)
        implies post1_self_.get_container(c_ptr).depth
            =~= post2_self_.get_container(c_ptr).depth by {
    assert(post2_self_.container_dom().contains(c_ptr));
};

// ---- processes_fields_unchanged: trigger pre_self_.get_proc(p_ptr) shared. ----
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr).pcid
            =~= post2_self_.get_proc(p_ptr).pcid by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr).ioid
            =~= post2_self_.get_proc(p_ptr).ioid by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr).owned_threads
            =~= post2_self_.get_proc(p_ptr).owned_threads by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr).dmd_paging_mode
            =~= post2_self_.get_proc(p_ptr).dmd_paging_mode by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr).depth
            =~= post2_self_.get_proc(p_ptr).depth by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr).parent
            =~= post2_self_.get_proc(p_ptr).parent by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};

// ---- threads_unchanged: trigger pre_self_.get_thread(t_ptr) shared. ----
assert forall|t_ptr: ThreadPtr|
    post1_self_.thread_dom().contains(t_ptr)
        implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(post2_self_.thread_dom().contains(t_ptr));
};

// ---- Parent process: explicit ensures pin .children@ to
// pre.get_proc(par_ptr).children@.remove_value(proc_ptr) for BOTH runs,
// and pin .children.len() to pre.children.len() - 1 for both runs. ----
assert(post1_self_.get_proc(par_ptr).children@
    =~= post2_self_.get_proc(par_ptr).children@);
assert(post1_self_.get_proc(par_ptr).children.len()
    == post2_self_.get_proc(par_ptr).children.len());

// ---- Non-parent processes: the per-non-parent ensures gives the FULL
// StaticLinkedList equality, post.get_proc(p).children == pre.get_proc(p).children. ----
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr) && p_ptr != par_ptr
        implies post1_self_.get_proc(p_ptr).children
            =~= post2_self_.get_proc(p_ptr).children by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};

// ---- subtree_set on the proc_ptr-uppertree: both ensures pin to
// pre.get_proc(p_p_ptr).subtree_set@.remove(proc_ptr). ----
assert forall|p_p_ptr: ProcPtr|
    pre_self_.get_proc(proc_ptr).uppertree_seq@.contains(p_p_ptr)
        implies post1_self_.get_proc(p_p_ptr).subtree_set@
            =~= post2_self_.get_proc(p_p_ptr).subtree_set@ by {
};

// ---- uppertree_seq on proc_dom: both ensures pin to pre.get_proc(p).uppertree_seq. ----
assert forall|p_ptr: ProcPtr|
    post1_self_.proc_dom().contains(p_ptr)
        implies post1_self_.get_proc(p_ptr).uppertree_seq
            =~= post2_self_.get_proc(p_ptr).uppertree_seq by {
    assert(post2_self_.proc_dom().contains(p_ptr));
};
